        B_BUT                                                                = 7486,  -- B-but...
        YOU_PEOPLE_ARE_NOTHING_BUT_PUPPETS_YOUR_STRINGS                      = 7487,  -- You people are nothing but puppets, your strings tied to the fingers of the terrestrial avatars, destined to a life of slavery. Why not open your eyes to the truth?
        NOW_THAT_YOU_REALIZE_YOUR_TRUE_ENEMIES_ARE                           = 7488,  -- Now that you realize your true enemies are the avatars who claim to protect you, your journey through the darkness is over.
        YOU_CAN_LEAVE_THE_REST_TO_ME_I                                       = 7489,  -- You can leave the rest to me. I shall change your destinies.
        ID_7490                                                              = 7490,  -- ...!
        THE_LIGHT_SELH_TEUS_HAS_GATHERED_FROM_THE                            = 7491,  -- The light Selh'teus has gathered from the mothercrystals... If the celestial capital of Al'Taieu still does exist, then the Zilart's plan is...
