        ARGH_I_M_ONLY_RECEIVING_PARTIAL_DATA_THERE                           = 7494,  -- Argh... I'm only receiving partial data... There's still too much interference coming from the fifth crystal...
        BUT_THAT_IMAGE_I_VE_SEEN_IT_SOMEWHERE                                = 7495,  -- But that image... I've seen it somewhere before... It was...the Chamber of Eventide. And that was Esha'ntarl!
